import shutil
import subprocess
from pathlib import Path

class DiskCleaner:
    def __init__(self):
        self.total_freed_bytes = 0

        # Các thư mục Temp thường xuyên phình to trên Windows
        self.temp_paths = [
            Path(os.environ.get('TEMP', 'C:\\Temp')),
            Path(os.environ.get('TMP', 'C:\\Windows\\Temp')),
            Path('C:\\Windows\\Prefetch'),
            Path('C:\\Windows\\SoftwareDistribution\\Download') # Nơi lưu file update Win
        ]

    def _format_size(self, size_in_bytes: float) -> str:
        """Định dạng byte sang MB/GB cho dễ nhìn"""
        for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
            if size_in_bytes < 1024.0:
                return f"{size_in_bytes:.2f} {unit}"
            size_in_bytes /= 1024.0

    def _get_dir_size(self, path: Path) -> int:
        """Lấy kích thước một thư mục"""
        total_size = 0
        try:
            for dirpath, _, filenames in os.walk(path):
                for f in filenames:
                    fp = os.path.join(dirpath, f)
                    if not os.path.islink(fp):
                        total_size += os.path.getsize(fp)
        except Exception:
            pass
        return total_size

    def clean_temp_folders(self):
        """Xóa các thư mục Temp của Windows"""
        print("\n🧹 Đang dọn dẹp các thư mục Temp hệ thống...")
        for path in self.temp_paths:
            if not path.exists():
                continue

            print(f"  - Quét: {path}")
            size_before = self._get_dir_size(path)
            deleted_count = 0

            try:
                for item in path.iterdir():
                    try:
                        if item.is_file() or item.is_symlink():
                            item.unlink()
                            deleted_count += 1
                        elif item.is_dir():
                            shutil.rmtree(item, ignore_errors=True)
                            deleted_count += 1
                    except Exception:
                        pass # Bỏ qua các file đang được OS sử dụng
            except PermissionError:
                print(f"  [!] Không có quyền truy cập: {path}")

            size_after = self._get_dir_size(path)
            freed = max(0, size_before - size_after)
            self.total_freed_bytes += freed
            print(f"    -> Đã xóa {deleted_count} mục. Giải phóng: {self._format_size(freed)}")

    def clean_dev_caches(self):
        """Gọi CLI để dọn cache của pip, uv, npm"""
        print("\n💻 Đang dọn dẹp bộ nhớ đệm (Cache) của Lập trình viên...")
        commands = [
            ("uv", ["uv", "cache", "clean"]),
            ("pip", ["pip", "cache", "purge"]),
            ("npm", ["npm", "cache", "clean", "--force"]),
            ("yarn", ["yarn", "cache", "clean"])
        ]

        for name, cmd in commands:
            print(f"  - Đang chạy: {' '.join(cmd)}")
            try:
                # Ẩn output để log sạch, timeout 30s
                subprocess.run(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=30)
                print(f"    -> {name} cache cleaned.")
                # Lệnh purge tự làm rỗng folder, không track byte trực tiếp được dễ dàng
                # Nên ta coi như một thao tác dọn dẹp vô hình.
            except FileNotFoundError:
                print(f"    -> {name} không được cài đặt. Bỏ qua.")
            except Exception as e:
                print(f"    -> Lỗi khi dọn {name}: {e}")

    def clean_docker(self):
        """Xóa Docker images/containers dangling"""
        print("\n🐳 Đang dọn dẹp Docker rác...")
        try:
            # system prune -f (force)
            cmd = ["docker", "system", "prune", "-a", "-f", "--volumes"]
            print(f"  - Đang chạy: {' '.join(cmd)}")
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=60)

            # Docker prune thường trả về thông tin đã giải phóng ở dòng cuối cùng
            output = result.stdout
            if "Total reclaimed space:" in output:
                reclaimed_line = [line for line in output.split('\n') if "Total reclaimed space:" in line]
                if reclaimed_line:
                    print(f"    -> {reclaimed_line[0]}")
            else:
                print("    -> Docker pruned.")
        except FileNotFoundError:
             print("    -> Docker không được cài đặt. Bỏ qua.")
        except Exception as e:
             print(f"    -> Lỗi khi dọn Docker: {e}")

    def run(self):
        print("================================================")
        print("🚀 BẮT ĐẦU CHƯƠNG TRÌNH DỌN DẸP Ổ C (DISK CLEANER)")
        print("================================================")

        self.clean_temp_folders()
        self.clean_dev_caches()
        self.clean_docker()

        print("\n================================================")
        print(f"✅ TỔNG KẾT: Đã dọn dẹp thành công các khu vực rác.")
        if self.total_freed_bytes > 0:
            print(f"🎉 Ước tính giải phóng tĩnh (từ Temp): {self._format_size(self.total_freed_bytes)}")
        print("Lưu ý: Không gian giải phóng từ Cache/Docker có thể chưa được tính vào con số trên, hãy mở ổ C để kiểm tra!")
        print("================================================")

if __name__ == "__main__":
    cleaner = DiskCleaner()
    cleaner.run()
